const items = $input.all();
const cfg = $('Konfiguracija1').first().json;
const SHEETS_URL = cfg.SHEETS_URL;

function toInt(value, fallback) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(1, Math.floor(parsed));
}

const batchSize = toInt(cfg.SHEETS_BATCH_SIZE, 40);

const rows = items.map((item) => {
  const d = item.json;
  return {
    Firma: (d.businessName || '').substring(0, 200),
    Website: (d.websiteDisplay || d.websiteUrl || 'NEMA SAJT').substring(0, 250),
    Adresa: (d.address || '').substring(0, 300),
    Telefon: d.phone || 'NEMA BROJ',
    Email: '',
    'PageSpeed Mobile': d.mobileScoreStr || 'N/A',
    Problemi: (d.websiteIssuesStr || '').substring(0, 500),
    'Email Poslan': '',
    'LinkedIn Poruka': '',
    'Call Skript': '',
    Status: 'Novi lead',
    'Follow-up 1': '',
    'Follow-up 2': '',
    Napomene: [
      d.targetSegment ? ('Nisa: ' + d.targetSegment) : '',
      d.marketCity && d.marketCountry ? ('Market: ' + d.marketCity + ', ' + d.marketCountry) : '',
      d.balkanScore !== undefined ? ('Balkan score: ' + d.balkanScore) : ''
    ].filter(Boolean).join(' | ')
  };
});

const batches = [];
for (let i = 0; i < rows.length; i += batchSize) {
  batches.push(rows.slice(i, i + batchSize));
}

const totalBatches = batches.length;

return batches.map((chunk, idx) => ({
  json: {
    sheetsUrl: SHEETS_URL,
    batchIndex: idx + 1,
    batchTotal: totalBatches,
    batchRows: chunk.length,
    sheetsBody: JSON.stringify({
      action: 'appendBatch',
      rows: chunk
    })
  }
}));

const config = $('Konfiguracija1').first().json;

function toInt(value, fallback) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(1, Math.floor(parsed));
}

function pickRandom(arr, count) {
  const clone = [...arr];
  for (let i = clone.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [clone[i], clone[j]] = [clone[j], clone[i]];
  }
  return clone.slice(0, count);
}

function randomFrom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

const wealthyCities = [
  { city: 'Zurich', country: 'Switzerland' },
  { city: 'Geneva', country: 'Switzerland' },
  { city: 'Basel', country: 'Switzerland' },
  { city: 'Zug', country: 'Switzerland' },
  { city: 'Munich', country: 'Germany' },
  { city: 'Frankfurt', country: 'Germany' },
  { city: 'Stuttgart', country: 'Germany' },
  { city: 'Dusseldorf', country: 'Germany' },
  { city: 'Hamburg', country: 'Germany' },
  { city: 'Berlin', country: 'Germany' },
  { city: 'Vienna', country: 'Austria' },
  { city: 'Salzburg', country: 'Austria' },
  { city: 'London', country: 'United Kingdom' },
  { city: 'Manchester', country: 'United Kingdom' },
  { city: 'Chicago', country: 'USA' },
  { city: 'New York', country: 'USA' },
  { city: 'Miami', country: 'USA' },
  { city: 'Toronto', country: 'Canada' },
  { city: 'Vancouver', country: 'Canada' },
  { city: 'Sydney', country: 'Australia' },
  { city: 'Melbourne', country: 'Australia' },
  { city: 'Dubai', country: 'UAE' }
];

const markets = [
  {
    segment: 'Construction',
    terms: [
      'construction company',
      'general contractor',
      'renovation company',
      'roofing contractor',
      'electrical contractor',
      'plumbing contractor',
      'Bauunternehmen',
      'Baufirma',
      'Sanierung Firma'
    ]
  },
  {
    segment: 'Real Estate',
    terms: [
      'real estate agency',
      'real estate broker',
      'property management',
      'commercial real estate',
      'Hausverwaltung',
      'Immobilienmakler',
      'Immobilienverwaltung'
    ]
  },
  {
    segment: 'Beauty Clinic',
    terms: [
      'beauty clinic',
      'medical spa',
      'skin clinic',
      'laser clinic',
      'aesthetic clinic',
      'Kosmetikstudio',
      'beauty salon'
    ]
  },
  {
    segment: 'Aesthetic Medicine',
    terms: [
      'aesthetic medicine clinic',
      'botox clinic',
      'dermatology aesthetic clinic',
      'plastic surgery clinic',
      'aesthetic doctor',
      'aesthetische medizin',
      'medizinische kosmetik'
    ]
  }
];

const diasporaSignals = [
  'serbian',
  'croatian',
  'bosnian',
  'montenegrin',
  'balkan',
  'ex yu',
  'jugoslav',
  'srpski',
  'hrvatski',
  'bosanski'
];

const surnameHints = [
  'Jovic', 'Petrovic', 'Nikolic', 'Markovic', 'Ilic', 'Kovacevic', 'Stankovic', 'Popovic', 'Vukovic',
  'Radovic', 'Savic', 'Jankovic', 'Djukic', 'Simic', 'Tomic', 'Milic', 'Ristic', 'Pavlovic',
  'Stojanovic', 'Filipovic', 'Lazic', 'Stefanovic', 'Matic', 'Peric', 'Knezevic', 'Krstic', 'Horvat',
  'Kovac', 'Hadzic', 'Selimovic', 'Martinovic', 'Berisha', 'Krasniqi', 'Hoxha', 'Gashi', 'Ahmeti'
];

function buildQuery(term, city, country, mode) {
  const base = `${term} ${city} ${country}`;
  if (mode === 'diaspora') {
    return `${base} ${randomFrom(diasporaSignals)}`;
  }
  if (mode === 'surname') {
    return `${term} ${randomFrom(surnameHints)} ${city} ${country}`;
  }
  return base;
}

const numCities = toInt(config.NUM_CITIES, 10);
const queriesPerCity = toInt(config.QUERIES_PER_CITY, 10);
const selectedCities = pickRandom(wealthyCities, Math.min(numCities, wealthyCities.length));
const flattenedMarkets = markets.flatMap((m) => m.terms.map((term) => ({ segment: m.segment, term })));

const rawQueries = [];

for (const city of selectedCities) {
  const cityQueries = [];

  for (const market of markets) {
    const term = randomFrom(market.terms);

    cityQueries.push({
      searchQuery: buildQuery(term, city.city, city.country, 'base'),
      targetSegment: market.segment,
      marketCity: city.city,
      marketCountry: city.country,
      queryIntent: 'base',
      usedSurnameHint: false,
      usedDiasporaSignal: false,
      GOOGLE_API_KEY: config.GOOGLE_API_KEY
    });

    if (Math.random() < 0.85) {
      cityQueries.push({
        searchQuery: buildQuery(term, city.city, city.country, 'diaspora'),
        targetSegment: market.segment,
        marketCity: city.city,
        marketCountry: city.country,
        queryIntent: 'diaspora',
        usedSurnameHint: false,
        usedDiasporaSignal: true,
        GOOGLE_API_KEY: config.GOOGLE_API_KEY
      });
    }
  }

  while (cityQueries.length < queriesPerCity) {
    const item = randomFrom(flattenedMarkets);
    const roll = Math.random();
    const mode = roll > 0.92 ? 'surname' : (roll > 0.65 ? 'diaspora' : 'base');

    cityQueries.push({
      searchQuery: buildQuery(item.term, city.city, city.country, mode),
      targetSegment: item.segment,
      marketCity: city.city,
      marketCountry: city.country,
      queryIntent: mode,
      usedSurnameHint: mode === 'surname',
      usedDiasporaSignal: mode === 'diaspora',
      GOOGLE_API_KEY: config.GOOGLE_API_KEY
    });
  }

  rawQueries.push(...cityQueries.slice(0, queriesPerCity));
}

const uniqueQueries = Array.from(
  new Map(rawQueries.map((q) => [q.searchQuery.toLowerCase(), q])).values()
);

return uniqueQueries.map((q) => ({ json: q }));

const config = $('Konfiguracija1').first().json;
const allItems = $input.all();
const queryItems = $('Generisi Pretrage1').all();

function toInt(value, fallback, min = 1) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.floor(parsed));
}

function toNum(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function normalize(text) {
  return String(text || '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/_/g, ' ')
    .toLowerCase();
}

function containsAny(text, keywords) {
  return keywords.some((k) => text.includes(k));
}

function detectSegmentFromText(text) {
  const segments = [
    {
      name: 'Construction',
      keys: ['construction', 'contractor', 'bau', 'renovation', 'roofing', 'plumbing', 'electrical', 'sanierung', 'builder']
    },
    {
      name: 'Real Estate',
      keys: ['real estate', 'estate agency', 'estate agent', 'property management', 'immobilien', 'hausverwaltung', 'broker']
    },
    {
      name: 'Beauty Clinic',
      keys: ['beauty clinic', 'medical spa', 'skin clinic', 'laser clinic', 'kosmetikstudio', 'beauty salon', 'kosmetik']
    },
    {
      name: 'Aesthetic Medicine',
      keys: ['aesthetic medicine', 'botox', 'dermatology', 'plastic surgery', 'aesthetische', 'medizinische kosmetik']
    }
  ];

  for (const segment of segments) {
    if (containsAny(text, segment.keys)) return segment.name;
  }

  return null;
}

function detectSegmentFromTypes(typesArr) {
  const types = (typesArr || []).map((t) => normalize(t));

  if (types.some((t) => ['general contractor', 'roofing contractor', 'electrician', 'plumber'].includes(t))) {
    return 'Construction';
  }

  if (types.some((t) => ['real estate agency', 'real estate consultant', 'property management company'].includes(t))) {
    return 'Real Estate';
  }

  if (types.some((t) => ['beauty salon', 'spa', 'hair care'].includes(t))) {
    return 'Beauty Clinic';
  }

  if (types.some((t) => ['doctor', 'health', 'hospital'].includes(t))) {
    return 'Aesthetic Medicine';
  }

  return null;
}

const excludeKeywords = [
  'restaurant', 'restoran', 'cafe', 'kafana', 'bar', 'pizza', 'burger',
  'bakery', 'hotel', 'hostel', 'night club', 'pub', 'school', 'kindergarten', 'university'
];

const balkanSignals = [
  'serb', 'srp', 'croat', 'hrvat', 'bosn', 'balkan', 'jugoslav', 'ex yu', 'montenegr', 'makedon', 'alban'
];

const surnameHints = [
  'jovic', 'petrovic', 'nikolic', 'markovic', 'ilic', 'kovacevic', 'stankovic', 'popovic', 'vukovic',
  'radovic', 'savic', 'jankovic', 'djukic', 'simic', 'tomic', 'milic', 'ristic', 'pavlovic',
  'stojanovic', 'filipovic', 'lazic', 'stefanovic', 'matic', 'peric', 'knezevic', 'krstic', 'horvat',
  'kovac', 'hadzic', 'selimovic', 'martinovic', 'berisha', 'krasniqi', 'hoxha', 'gashi', 'ahmeti'
];

const minScore = toInt(config.MIN_BALKAN_SCORE, 2, 1);
const maxLeads = toInt(config.MAX_LEADS_PER_RUN, 220, 1);
const minReviewCount = toInt(config.MIN_REVIEW_COUNT, 8, 0);
const minRating = toNum(config.MIN_RATING, 3.8);
const maxPerCitySegment = toInt(config.MAX_LEADS_PER_CITY_SEGMENT, 12, 1);

const dedupe = new Map();

for (let i = 0; i < allItems.length; i += 1) {
  const item = allItems[i].json || {};
  const queryMeta = queryItems[i] ? (queryItems[i].json || {}) : {};
  const queryText = normalize(queryMeta.searchQuery || '');
  const results = Array.isArray(item.results) ? item.results : [];

  if (item.status && !['OK', 'ZERO_RESULTS'].includes(String(item.status))) {
    continue;
  }

  for (const place of results) {
    if (!place.place_id) continue;

    const businessName = place.name || '';
    const address = place.formatted_address || '';
    const businessTypesArr = Array.isArray(place.types) ? place.types : [];
    const rating = Number(place.rating || 0);
    const reviewCount = Number(place.user_ratings_total || 0);

    if (reviewCount > 0 && reviewCount < minReviewCount) continue;
    if (rating > 0 && rating < minRating) continue;

    const allText = normalize([businessName, address, businessTypesArr.join(' ')].join(' '));
    if (containsAny(allText, excludeKeywords)) continue;

    const segmentByText = detectSegmentFromText(allText);
    const segmentByTypes = detectSegmentFromTypes(businessTypesArr);
    const querySegment = queryMeta.targetSegment || '';

    const targetSegment = segmentByText || segmentByTypes || '';
    if (!targetSegment) continue;
    if (querySegment && targetSegment !== querySegment) continue;

    let balkanScore = 0;

    if (queryMeta.queryIntent === 'surname') balkanScore += 2;
    if (queryMeta.queryIntent === 'diaspora') balkanScore += 1;

    if (containsAny(queryText, balkanSignals) || containsAny(queryText, surnameHints)) balkanScore += 1;
    if (containsAny(allText, balkanSignals)) balkanScore += 2;

    const nameOnly = normalize(businessName);
    if (containsAny(nameOnly, surnameHints)) balkanScore += 2;

    if (/\b[a-z]{3,}(ovic|evic|ic|vich|ski|ska)\b/.test(nameOnly)) {
      balkanScore += 2;
    }

    if (reviewCount >= 80) balkanScore += 1;
    if (rating >= 4.6) balkanScore += 1;

    const candidate = {
      businessName,
      address,
      placeId: place.place_id,
      rating: rating || null,
      reviewCount,
      businessTypes: businessTypesArr.join(', '),
      targetSegment,
      balkanScore,
      marketCity: queryMeta.marketCity || '',
      marketCountry: queryMeta.marketCountry || '',
      searchQuery: queryMeta.searchQuery || '',
      queryIntent: queryMeta.queryIntent || 'base',
      GOOGLE_API_KEY: config.GOOGLE_API_KEY
    };

    const prev = dedupe.get(candidate.placeId);
    if (!prev) {
      dedupe.set(candidate.placeId, candidate);
      continue;
    }

    const better =
      candidate.balkanScore > prev.balkanScore ||
      (candidate.balkanScore === prev.balkanScore && candidate.reviewCount > prev.reviewCount) ||
      (candidate.balkanScore === prev.balkanScore && candidate.reviewCount === prev.reviewCount && (candidate.rating || 0) > (prev.rating || 0));

    if (better) {
      dedupe.set(candidate.placeId, candidate);
    }
  }
}

const sorted = Array.from(dedupe.values())
  .sort((a, b) =>
    (b.balkanScore - a.balkanScore) ||
    (b.reviewCount - a.reviewCount) ||
    ((b.rating || 0) - (a.rating || 0))
  );

const strict = sorted.filter((x) => x.balkanScore >= minScore);
const relaxed = sorted.filter((x) => x.balkanScore >= Math.max(1, minScore - 1));
const selectedPool = strict.length > 0 ? strict : (relaxed.length > 0 ? relaxed : sorted.filter((x) => x.balkanScore >= 1));

const counters = new Map();
const diversified = [];

for (const lead of selectedPool) {
  const key = `${lead.marketCity}__${lead.targetSegment}`;
  const count = counters.get(key) || 0;
  if (count >= maxPerCitySegment) continue;

  counters.set(key, count + 1);
  diversified.push(lead);

  if (diversified.length >= maxLeads) break;
}

if (diversified.length === 0) {
  return [{ json: { DEBUG: true, message: 'Nema leadova: Google vratio 0 ili je filter prejak.' } }];
}

return diversified.map((lead) => ({ json: lead }));

const placeDetailsItems = $input.all();
const originalLeads = $('Parsiraj Rezultate1').all();
const config = $('Konfiguracija1').first().json;

function normalize(text) {
  return String(text || '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/_/g, ' ')
    .toLowerCase();
}

function containsAny(text, keywords) {
  return keywords.some((k) => text.includes(k));
}

function getHost(url) {
  try {
    return new URL(url).hostname.toLowerCase();
  } catch {
    return '';
  }
}

const balkanSignals = [
  'serb', 'srp', 'croat', 'hrvat', 'bosn', 'balkan', 'jugoslav', 'ex yu', 'montenegr', 'makedon', 'alban'
];

const surnameHints = [
  'jovic', 'petrovic', 'nikolic', 'markovic', 'ilic', 'kovacevic', 'stankovic', 'popovic', 'vukovic',
  'radovic', 'savic', 'jankovic', 'djukic', 'simic', 'tomic', 'milic', 'ristic', 'pavlovic',
  'stojanovic', 'filipovic', 'lazic', 'stefanovic', 'matic', 'peric', 'knezevic', 'krstic', 'horvat',
  'kovac', 'hadzic', 'selimovic', 'martinovic', 'berisha', 'krasniqi', 'hoxha', 'gashi', 'ahmeti'
];

const socialHosts = [
  'facebook.com', 'm.facebook.com', 'instagram.com', 'linkedin.com',
  'tiktok.com', 'youtube.com', 'x.com', 'twitter.com'
];

const balkanTlds = ['.rs', '.hr', '.ba', '.me', '.mk', '.si', '.al'];

const keepNoWebsite = Boolean(config.KEEP_LEADS_WITHOUT_WEBSITE ?? true);

const leadByPlaceId = new Map();
for (const item of originalLeads) {
  const lead = item.json;
  if (lead?.placeId) {
    leadByPlaceId.set(lead.placeId, lead);
  }
}

const results = [];

for (let i = 0; i < placeDetailsItems.length; i += 1) {
  const details = placeDetailsItems[i].json?.result || {};
  const placeId = details.place_id || '';
  const lead = leadByPlaceId.get(placeId) || (originalLeads[i] ? originalLeads[i].json : {});

  if (lead.DEBUG) continue;

  const businessName = details.name || lead.businessName || '';
  const address = details.formatted_address || lead.address || '';

  if (!businessName) continue;

  let websiteUrl = details.website || lead.websiteUrl || null;
  let websiteHost = websiteUrl ? getHost(websiteUrl) : '';

  const isSocialWebsite = websiteHost
    ? socialHosts.some((host) => websiteHost === host || websiteHost.endsWith(`.${host}`))
    : false;

  if (isSocialWebsite) {
    websiteUrl = null;
    websiteHost = '';
  }

  const hasWebsite = !!websiteUrl;
  if (!hasWebsite && !keepNoWebsite) continue;

  let balkanScore = Number(lead.balkanScore || 0);
  const mergedText = normalize([businessName, address, websiteUrl || ''].join(' '));

  if (containsAny(mergedText, balkanSignals)) balkanScore += 2;
  if (containsAny(normalize(businessName), surnameHints)) balkanScore += 2;
  if (/\b[a-z]{3,}(ovic|evic|ic|vich|ski|ska)\b/.test(normalize(businessName))) balkanScore += 2;

  if (websiteHost && balkanTlds.some((tld) => websiteHost.endsWith(tld))) {
    balkanScore += 2;
  }

  if (balkanScore < 1) continue;

  results.push({
    json: {
      businessName,
      address,
      placeId: lead.placeId || placeId,
      rating: lead.rating || null,
      reviewCount: lead.reviewCount || 0,
      businessTypes: lead.businessTypes || '',
      targetSegment: lead.targetSegment || '',
      marketCity: lead.marketCity || '',
      marketCountry: lead.marketCountry || '',
      balkanScore,
      phone: details.international_phone_number || details.formatted_phone_number || null,
      websiteUrl,
      websiteHost,
      websiteDisplay: hasWebsite ? websiteUrl : 'NEMA SAJT',
      hasWebsite,
      GOOGLE_API_KEY: config.GOOGLE_API_KEY
    }
  });
}

return results.length > 0
  ? results
  : [{ json: { DEBUG: true, message: 'Nema leadova posle Place Details (proveri Places API key).' } }];

const config = $('Konfiguracija1').first().json;
const pageSpeedEnabled = Boolean(config.ENABLE_PAGESPEED ?? false);

const psItems = $input.all();
const leadItems = $('Spoji Detalje1').all();
const results = [];

for (let i = 0; i < psItems.length; i += 1) {
  const psData = psItems[i].json || {};
  const lead = leadItems[i] ? leadItems[i].json : {};

  if (lead.DEBUG) continue;

  const issues = [];
  const hasWebsite = !!lead.hasWebsite;
  const pageSpeedError = psData?.error?.message || '';

  let mobileScoreNum = null;

  if (hasWebsite) {
    const scoreRaw = psData?.lighthouseResult?.categories?.performance?.score;
    if (typeof scoreRaw === 'number') {
      mobileScoreNum = Math.round(scoreRaw * 100);
    }

    if (mobileScoreNum !== null) {
      if (mobileScoreNum < 40) issues.push('Very slow mobile site');
      else if (mobileScoreNum < 60) issues.push('Slow mobile site');
      else if (mobileScoreNum < 75) issues.push('Average mobile speed');
    } else if (!pageSpeedEnabled) {
      issues.push('PageSpeed disabled in config');
    } else if (pageSpeedError) {
      const msg = String(pageSpeedError).toLowerCase();
      if (msg.includes('disabled') || msg.includes('accessnotconfigured') || msg.includes('not been used')) {
        issues.push('PageSpeed API is not enabled');
      } else if (msg.includes('quota') || msg.includes('rate') || msg.includes('limit')) {
        issues.push('PageSpeed quota limit');
      } else {
        issues.push('PageSpeed unavailable');
      }
    } else {
      issues.push('PageSpeed unavailable');
    }

    const audits = psData?.lighthouseResult?.audits || {};
    if (audits['uses-optimized-images']?.score < 0.5) issues.push('Images not optimized');
    if (audits['unused-css-rules']?.score < 0.5) issues.push('Unused CSS slows site');
    if (audits['render-blocking-resources']?.score < 0.5) issues.push('Render-blocking resources');

    if (lead.websiteUrl && lead.websiteUrl.startsWith('http://')) {
      issues.push('No SSL (http)');
    }

    if (issues.length === 0) issues.push('Website can still be improved');
  } else {
    issues.push('NEMA SAJT');
  }

  const mobileScoreStr = hasWebsite
    ? (mobileScoreNum !== null ? String(mobileScoreNum) : 'N/A')
    : 'N/A (nema sajt)';

  results.push({
    json: {
      businessName: lead.businessName || '',
      address: lead.address || '',
      phone: lead.phone || null,
      websiteUrl: lead.websiteUrl || null,
      websiteHost: lead.websiteHost || '',
      websiteDisplay: lead.websiteDisplay || (lead.websiteUrl || 'NEMA SAJT'),
      hasWebsite,
      targetSegment: lead.targetSegment || '',
      marketCity: lead.marketCity || '',
      marketCountry: lead.marketCountry || '',
      rating: lead.rating || null,
      reviewCount: lead.reviewCount || 0,
      businessTypes: lead.businessTypes || '',
      balkanScore: lead.balkanScore || 0,
      mobileScore: mobileScoreNum,
      mobileScoreStr,
      websiteIssues: issues,
      websiteIssuesStr: issues.join(' | '),
      mainIssue: issues[0] || (hasWebsite ? 'Website optimization' : 'NEMA SAJT')
    }
  });
}

return results;
